package search

import (
	"math"
	"strings"
)

// SearchResult is a ranked search hit.
type SearchResult struct {
	QualifiedID  string   `json:"qualifiedId"`
	DocumentSlug string   `json:"documentSlug"`
	SectionID    string   `json:"sectionId"`
	Title        string   `json:"title"`
	Score        float64  `json:"score"`
	Snippet      string   `json:"snippet"`
	Scope        string   `json:"scope"`
	Kind         string   `json:"kind"`
	Tags         []string `json:"tags"`
}

// SearchResponse wraps search results with metadata.
type SearchResponse struct {
	Results      []SearchResult `json:"results"`
	TotalMatches int            `json:"totalMatches"`
	SearchTimeMs int64          `json:"searchTimeMs"`
	IndexState   string         `json:"indexState"`
	BM25Only     bool           `json:"bm25Only,omitempty"`
}

// ReadResponse wraps a full section retrieval.
type ReadResponse struct {
	Mode     string         `json:"mode"`
	Found    bool           `json:"found"`
	Section  *ReadSection   `json:"section,omitempty"`
	Context  []ReadSection  `json:"context,omitempty"`
	Document *ReadDocMeta   `json:"document,omitempty"`
	Sections []SectionEntry `json:"sections,omitempty"`
	Error    *ReadError     `json:"error,omitempty"`
}

// ReadSection holds full section content.
type ReadSection struct {
	QualifiedID  string   `json:"qualifiedId"`
	DocumentSlug string   `json:"documentSlug"`
	SectionID    string   `json:"sectionId"`
	Title        string   `json:"title"`
	Content      string   `json:"content"`
	Scope        string   `json:"scope"`
	Kind         string   `json:"kind"`
	Tags         []string `json:"tags"`
	Position     int      `json:"position"`
}

// ReadDocMeta holds document-level metadata for TOC mode.
type ReadDocMeta struct {
	Slug         string   `json:"slug"`
	Title        string   `json:"title"`
	Scope        string   `json:"scope"`
	Kind         string   `json:"kind"`
	Tags         []string `json:"tags"`
	SectionCount int      `json:"sectionCount"`
}

// SectionEntry is a table-of-contents item.
type SectionEntry struct {
	SectionID   string `json:"sectionId"`
	Title       string `json:"title"`
	QualifiedID string `json:"qualifiedId"`
}

// ReadError provides disambiguation for ambiguous IDs.
type ReadError struct {
	Code    string   `json:"code"`
	Message string   `json:"message"`
	Options []string `json:"options"`
}

// GenerateSnippet produces a truncated preview of content.
// Truncates at maxLen characters on a word boundary, appending "..." if truncated.
func GenerateSnippet(content string, maxLen int) string {
	content = strings.TrimSpace(content)
	if len(content) <= maxLen {
		return content
	}

	// Find last space before the boundary
	truncated := content[:maxLen]
	lastSpace := strings.LastIndex(truncated, " ")
	if lastSpace > maxLen/2 {
		truncated = truncated[:lastSpace]
	}

	return strings.TrimSpace(truncated) + "..."
}

// RoundScore rounds a float64 to 4 decimal places.
func RoundScore(score float64) float64 {
	return math.Round(score*10000) / 10000
}
